import { useState } from "react";
import { useNavigate } from "react-router-dom";
import { useData } from "../contexts/DataContext";
import { MapPin, User, Check } from "lucide-react";

function SuccessModal({ onClose }) {
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center">
      {/* Backdrop */}
      <div
        className="absolute inset-0 bg-black/30 backdrop-blur-sm"
        onClick={onClose}
      />

      {/* Modal Card */}
      <div className="relative bg-white rounded-2xl border-2 border-blue-400 shadow-2xl w-full max-w-2xl mx-6 py-20 px-10 flex flex-col items-center gap-8 animate-in fade-in zoom-in-95 duration-200">
        {/* Green check circle */}
        <div className="w-36 h-36 rounded-full bg-green-100 border-4 border-green-500 flex items-center justify-center">
          <Check className="w-16 h-16 text-green-500 stroke-[2.5]" />
        </div>

        {/* Text */}
        <div className="flex flex-col items-center gap-3 text-center">
          <h2 className="text-4xl font-extrabold text-gray-800 tracking-wide uppercase">
            Verifikasi Pesanan Berhasil
          </h2>
          <p className="text-sm font-semibold tracking-widest text-gray-400 uppercase">
            Silahkan Melihat Riwayat Di Status Pengiriman
          </p>
        </div>
      </div>
    </div>
  );
}

export default function DataPesanan() {
  const { orders } = useData();
  const navigate = useNavigate();
  const [selectedOrder, setSelectedOrder] = useState(orders[0] || null);
  const [agreed, setAgreed] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);

  const handleVerifikasi = () => {
    if (!agreed || !selectedOrder) return;
    setShowSuccess(true);
  };

  const handleCloseModal = () => {
    setShowSuccess(false);
    navigate(`/pesanan/${selectedOrder?.id}/verifikasi`);
  };

  return (
    <div className="max-w-[1200px]" data-testid="data-pesanan-page">
      {showSuccess && <SuccessModal onClose={handleCloseModal} />}

      <h1 className="text-3xl font-extrabold text-gray-900">Data Pemesanan</h1>
      <p className="text-sm text-gray-500 mt-1 mb-8">Semua Pesanan Masuk</p>

      <div className="flex gap-6">
        {/* LEFT COLUMN */}
        <div className="flex flex-col gap-6 flex-1">

          {/* Card: Rute Pengiriman */}
          <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
            <p className="text-[11px] font-bold tracking-widest text-gray-400 uppercase mb-5">
              Rute Pengiriman
            </p>

            <div className="flex flex-col gap-0">
              {/* Titik Muat */}
              <div className="flex gap-4 items-start">
                <div className="flex flex-col items-center">
                  <div className="w-8 h-8 rounded-full border-2 border-amber-400 bg-white flex items-center justify-center">
                    <div className="w-3 h-3 rounded-full bg-amber-400" />
                  </div>
                  <div className="w-0.5 h-10 bg-gray-200 my-1" />
                </div>
                <div className="pb-4">
                  <p className="text-[10px] font-bold tracking-widest text-amber-500 uppercase mb-1">
                    Titik Muat — {selectedOrder?.originCity || "Jakarta Utara"}
                  </p>
                  <p className="font-bold text-gray-900 text-base">
                    {selectedOrder?.originName || "Kawasan Industri Pulogadung"}
                  </p>
                  <p className="text-sm text-gray-500 mt-0.5">
                    {selectedOrder?.originAddress || "Blok C No. 12, Pergudangan Logistics, Jakarta 13920"}
                  </p>
                </div>
              </div>

              {/* Titik Bongkar */}
              <div className="flex gap-4 items-start">
                <div className="flex flex-col items-center">
                  <div className="w-8 h-8 rounded-full bg-amber-400 flex items-center justify-center">
                    <MapPin className="w-4 h-4 text-white" />
                  </div>
                </div>
                <div>
                  <p className="text-[10px] font-bold tracking-widest text-amber-500 uppercase mb-1">
                    Titik Bongkar — {selectedOrder?.destCity || "Surabaya"}
                  </p>
                  <p className="font-bold text-gray-900 text-base">
                    {selectedOrder?.destName || "Margomulyo Permai"}
                  </p>
                  <p className="text-sm text-gray-500 mt-0.5">
                    {selectedOrder?.destAddress || "Jl. Greges Jaya II, Pergudangan B-14, Surabaya 60183"}
                  </p>
                </div>
              </div>
            </div>
          </div>

          {/* Card: Informasi Pengantar */}
          <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
            <p className="text-[11px] font-bold tracking-widest text-gray-400 uppercase mb-5">
              Informasi Pengantar
            </p>
            <div className="flex gap-5 items-start">
              <div className="w-20 h-20 rounded-xl bg-gray-100 flex items-center justify-center shrink-0">
                <User className="w-9 h-9 text-gray-400" />
              </div>
              <div className="flex flex-col gap-3 flex-1">
                <div>
                  <p className="text-[10px] font-bold tracking-widest text-gray-500 uppercase mb-1">
                    Nama Driver
                  </p>
                  <div className="bg-gray-100 rounded-lg px-4 py-2 text-sm text-gray-400">
                    {selectedOrder?.driverName || "cth: Budi"}
                  </div>
                </div>
                <div>
                  <p className="text-[10px] font-bold tracking-widest text-gray-500 uppercase mb-1">
                    Plat Nomor
                  </p>
                  <div className="bg-gray-100 rounded-lg px-4 py-2 text-sm text-gray-400">
                    {selectedOrder?.plateNumber || "cth: Bk 4511 ia"}
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* RIGHT COLUMN */}
        <div className="w-[340px] shrink-0">
          <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6 flex flex-col gap-6">
            <div className="flex gap-3 items-start">
              <input
                type="checkbox"
                id="agree"
                checked={agreed}
                onChange={(e) => setAgreed(e.target.checked)}
                className="mt-1 w-4 h-4 accent-amber-500 cursor-pointer"
              />
              <label htmlFor="agree" className="text-sm text-gray-600 leading-relaxed cursor-pointer">
                Saya menyatakan bahwa seluruh informasi di atas adalah benar
                dan saya menyetujui{" "}
                <span className="text-amber-500 font-semibold">
                  Syarat &amp; Ketentuan
                </span>{" "}
                pengiriman LogisticsLedger.
              </label>
            </div>

            <div className="flex gap-3 mt-2">
              <button
                onClick={() => navigate(-1)}
                className="flex-1 h-14 rounded-xl border border-gray-200 text-sm font-semibold text-gray-700 hover:bg-gray-50 transition-colors"
              >
                Kembali
              </button>
              <button
                onClick={handleVerifikasi}
                disabled={!agreed}
                data-testid="verifikasi-btn"
                className="flex-1 h-14 rounded-xl bg-amber-400 hover:bg-amber-500 disabled:opacity-40 disabled:cursor-not-allowed text-white text-[11px] font-extrabold tracking-widest uppercase transition-colors"
              >
                Verifikasi<br />Pesanan
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
